import{_ as e,c as a,o as r,d as c}from"./app.661b9247.js";const m=JSON.parse('{"title":"electron-packager打包配置","description":"","frontmatter":{},"headers":[{"level":3,"title":"electron-packager：https://github.com/electron/electron-packager","slug":"electron-packager-https-github-com-electron-electron-packager","link":"#electron-packager-https-github-com-electron-electron-packager","children":[]},{"level":3,"title":"electron-packager配置文档：npm.im/electron-packager","slug":"electron-packager配置文档-npm-im-electron-packager","link":"#electron-packager配置文档-npm-im-electron-packager","children":[]},{"level":3,"title":"electron-packager npm：https://www.npmjs.com/package/electron-packager","slug":"electron-packager-npm-https-www-npmjs-com-package-electron-packager","link":"#electron-packager-npm-https-www-npmjs-com-package-electron-packager","children":[]},{"level":3,"title":"使用electron-packager打包：","slug":"使用electron-packager打包","link":"#使用electron-packager打包","children":[]}],"relativePath":"Document/Electron/electron-packager打包配置.md","lastUpdated":1664182267000}'),t={name:"Document/Electron/electron-packager打包配置.md"},p=c('<h1 id="electron-packager打包配置" tabindex="-1">electron-packager打包配置 <a class="header-anchor" href="#electron-packager打包配置" aria-hidden="true">#</a></h1><h3 id="electron-packager-https-github-com-electron-electron-packager" tabindex="-1">electron-packager：<a href="https://github.com/electron/electron-packager" target="_blank" rel="noreferrer">https://github.com/electron/electron-packager</a> <a class="header-anchor" href="#electron-packager-https-github-com-electron-electron-packager" aria-hidden="true">#</a></h3><h3 id="electron-packager配置文档-npm-im-electron-packager" tabindex="-1">electron-packager配置文档：<a href="https://npm.im/electron-packager" title="https://npm.im/electron-packager" target="_blank" rel="noreferrer">npm.im/electron-packager</a> <a class="header-anchor" href="#electron-packager配置文档-npm-im-electron-packager" aria-hidden="true">#</a></h3><h3 id="electron-packager-npm-https-www-npmjs-com-package-electron-packager" tabindex="-1">electron-packager npm：<a href="https://www.npmjs.com/package/electron-packager" target="_blank" rel="noreferrer">https://www.npmjs.com/package/electron-packager</a> <a class="header-anchor" href="#electron-packager-npm-https-www-npmjs-com-package-electron-packager" aria-hidden="true">#</a></h3><hr><h3 id="使用electron-packager打包" tabindex="-1">使用electron-packager打包： <a class="header-anchor" href="#使用electron-packager打包" aria-hidden="true">#</a></h3><p>使用electron-packager打包特点：操作简单，打包后的目录就是程序的运行目录，相当于已经安装过，不用安装操作后才能运行，如果需要打包成安装器，需要使用electron-builder打包。</p><h5 id="_1、安装electron-packager-npm-install-electron-packager-save-dev" tabindex="-1">1、安装electron-packager npm install electron-packager --save-dev <a class="header-anchor" href="#_1、安装electron-packager-npm-install-electron-packager-save-dev" aria-hidden="true">#</a></h5><p>npm install electron-packager -g</p><h5 id="_2、快速打包命令-electron-packager" tabindex="-1">2、快速打包命令： electron-packager . <a class="header-anchor" href="#_2、快速打包命令-electron-packager" aria-hidden="true">#</a></h5><h5 id="_3、使用配置文件打包" tabindex="-1">3、使用配置文件打包： <a class="header-anchor" href="#_3、使用配置文件打包" aria-hidden="true">#</a></h5><h6 id="在项目的package-json文件中的scipts节点中添加代码" tabindex="-1">在项目的package.json文件中的scipts节点中添加代码 <a class="header-anchor" href="#在项目的package-json文件中的scipts节点中添加代码" aria-hidden="true">#</a></h6><p><code>electron-packager --platform= --arch= --out=out --icon=assets/app.ico --asar --overwrite --ignore=.git</code></p><ul><li><p>sourcedir：项目源文件所在路径（唯一的必须参数）</p></li><li><p>appname：项目名称（直接使用package.json文件中的name属性更方便）</p></li><li><p>platform：要构建哪个平台的应用（Windows、Mac 还是 Linux）</p></li><li><p>arch：构建架构 包含ia32,x64,armv7l,arm64</p></li><li><p>out：打包后的地址</p></li><li><p>icon：打包图标</p></li><li><p>asar：是否生成app.asar, 不然就是自己的源码</p></li><li><p>overwrite：覆盖上次打包</p></li><li><p>ignore：不进行打包的文件</p></li></ul><p>打包的路径不能出现中文或者特殊字符，第一次打包需要下载二进制的包耗时会久一些，以后走缓存就快的多了。</p><h6 id="下面是在设置了比较简单的打包代码-在scipts节点添加下面代码" tabindex="-1">下面是在设置了比较简单的打包代码（在scipts节点添加下面代码）： <a class="header-anchor" href="#下面是在设置了比较简单的打包代码-在scipts节点添加下面代码" aria-hidden="true">#</a></h6><p><code>&quot;packager&quot;: &quot;electron-packager ./ testapp --win --out ./outputs&quot;</code></p><ul><li><p>./：sourcedir，项目路径</p></li><li><p>testapp：appname，打包后可执行程序(.exe)的名字</p></li><li><p>–win：platform，构建win平台的打包</p></li><li><p>–out：打包后的地址，./outputs 就是打包后的地址</p></li></ul><p>4、配置完package.json文件后就可以使用命令<code>npm run packager</code>打包了</p><p>打包后跟目录生成outputs文件夹：</p><p>目录里面exe就是打包后可执行程序文件，</p>',21),n=[p];function l(o,i,s,g,h,k){return r(),a("div",null,n)}const u=e(t,[["render",l]]);export{m as __pageData,u as default};
